module RefModule(
    Y ,
    A1,
    A2,
    B1
);// Module ports
    output Y ;
    input  A1;
    input  A2;
    input  B1;

    // Module supplies
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Local signals
    wire or0_out    ;
    wire nand0_out_Y;

    // Cells
    bufif1 buf0(Y, nand0_out_Y, 1'b1);
    nand   nand0(nand0_out_Y, B1, or0_out);
    or     or0(or0_out, A2, A1);

endmodule
